28	// SessionLogExcerptReader reads a bounded excerpt from a session log path.
29	// The default implementation searches the project agent log dir for a
30	// matching agent-*.jsonl or svc-*.jsonl file.
31	type SessionLogExcerptReader interface {
32		ReadSessionLogExcerpt(ctx context.Context, projectRoot, sessionID string, maxBytes int) (string, error)
33	}
34	
35	type fileSessionLogExcerptReader struct{}
36	
37	func (fileSessionLogExcerptReader) ReadSessionLogExcerpt(ctx context.Context, projectRoot, sessionID string, maxBytes int) (string, error) {
38		if ctx != nil {
39			if err := ctx.Err(); err != nil {
40				return "", err
41			}
42		}
43		path, ok := resolveSessionLogPath(projectRoot, sessionID)
44		if !ok {
45			return "", os.ErrNotExist
46		}
47		return readBoundedFileTail(path, maxBytes)
48	}
