148	func buildPostAttemptTriagePrompt(ctx context.Context, projectRoot string, b *bead.Bead, report ExecuteBeadReport, reader SessionLogExcerptReader, eventLister interface {
149		Events(id string) ([]bead.BeadEvent, error)
150	}) (string, error) {
151		env := triagePromptEnvelope{
152			Bead: triagePromptBead{
153				ID:           b.ID,
154				Title:        strings.TrimSpace(b.Title),
155				Status:       strings.TrimSpace(b.Status),
156				Priority:     b.Priority,
157				IssueType:    strings.TrimSpace(b.IssueType),
158				Labels:       append([]string(nil), b.Labels...),
159				Parent:       strings.TrimSpace(b.Parent),
160				Description:  strings.TrimSpace(b.Description),
161				Acceptance:   strings.TrimSpace(b.Acceptance),
162				Notes:        strings.TrimSpace(b.Notes),
163				Dependencies: append([]bead.Dependency(nil), b.Dependencies...),
164			},
165			ExecuteBead: report,
166			ProjectRoot: projectRoot,
167		}
168		if len(b.Extra) > 0 {
169			env.Bead.Extra = make(map[string]any, len(b.Extra))
170			for k, v := range b.Extra {
171				if k == "events" || k == "events_attachment" {
172					continue
173				}
174				env.Bead.Extra[k] = v
175			}
176		}
177	
178		if eventLister != nil {
179			events, err := eventLister.Events(b.ID)
180			if err == nil && len(events) > 0 {
181				start := len(events) - maxTriageEventCount
182				if start < 0 {
183					start = 0
184				}
185				env.RecentEvents = make([]bead.BeadEvent, 0, len(events)-start)
186				for _, ev := range events[start:] {
187					env.RecentEvents = append(env.RecentEvents, clampTriageEvent(ev))
188				}
189			}
190		}
191	
192		if report.SessionID != "" && reader != nil {
193			excerpt, err := reader.ReadSessionLogExcerpt(ctx, projectRoot, report.SessionID, defaultSessionLogExcerptBytes)
194			if err == nil && strings.TrimSpace(excerpt) != "" {
195				env.SessionExcerpt = excerpt
196				if path, ok := resolveSessionLogPath(projectRoot, report.SessionID); ok {
197					env.SessionLogPath = path
198				}
199			}
200		}
201	
202		body, err := json.MarshalIndent(env, "", "  ")
203		if err != nil {
204			return "", err
205		}
206	
207		var sb strings.Builder
208		sb.WriteString("MODE: triage\n")
209		sb.WriteString("You are the bead-lifecycle skill (" + postAttemptTriageSkillName + "). Classify the outcome of the attempt and return exactly one JSON object.\n")
210		sb.WriteString("Return structured JSON with the fields classification, recommended_action, rationale, suggested_amendments, suggested_followup_beads.\n")
211		sb.WriteString("Required output shape example: {\"classification\":\"transport\",\"recommended_action\":\"release_claim_retry\",\"rationale\":\"transient provider failure\",\"suggested_amendments\":[],\"suggested_followup_beads\":[]}\n")
212		sb.WriteString("Array fields must be arrays; use [] when none are needed.\n")
213		sb.WriteString("Use only the documented classifications and recommended_action values from the skill contract.\n")
214		sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
215		sb.WriteString("```json\n")
216		sb.Write(body)
217		sb.WriteString("\n```\n")
218		return sb.String(), nil
219	}
