221	func triageResultOutput(result *Result) (string, error) {
222		if result == nil {
223			return "", fmt.Errorf("triage hook: empty runner result")
224		}
225		text := strings.TrimSpace(result.CondensedOutput)
226		if text == "" {
227			text = strings.TrimSpace(result.Output)
228		}
229		return text, nil
230	}
