298	type triageResultRaw struct {
299		Classification         string          `json:"classification,omitempty"`
300		RecommendedAction      string          `json:"recommended_action,omitempty"`
301		Rationale              string          `json:"rationale,omitempty"`
302		SuggestedAmendments    json.RawMessage `json:"suggested_amendments,omitempty"`
303		SuggestedFollowupBeads json.RawMessage `json:"suggested_followup_beads,omitempty"`
304	}
305	
306	func decodeTriageResult(payload string) TriageResult {
307		var raw triageResultRaw
308		if err := json.Unmarshal([]byte(payload), &raw); err != nil {
309			return malformedTriageResult("json", "invalid JSON object", payload)
310		}
311	
312		out := TriageResult{
313			Classification:    strings.TrimSpace(raw.Classification),
314			RecommendedAction: strings.TrimSpace(raw.RecommendedAction),
315			Rationale:         strings.TrimSpace(raw.Rationale),
316		}
317		out.SuggestedAmendments = []TriageAmendment{}
318		out.SuggestedFollowupBeads = []FollowupBead{}
319	
320		amendments, warnings := decodeTriageAmendments(raw.SuggestedAmendments)
321		out.SuggestedAmendments = amendments
322		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
323	
324		followups, warnings := decodeTriageFollowupBeads(raw.SuggestedFollowupBeads)
325		out.SuggestedFollowupBeads = followups
326		out.DecodeWarnings = append(out.DecodeWarnings, warnings...)
327	
328		out = normalizeTriageResult(out)
329		out = addTriageRequiredFieldWarnings(out)
330		return out
331	}
332	
333	func normalizeTriageResult(in TriageResult) TriageResult {
334		in.Classification = strings.TrimSpace(in.Classification)
335		in.RecommendedAction = strings.TrimSpace(in.RecommendedAction)
336		in.Rationale = strings.TrimSpace(in.Rationale)
337		if in.SuggestedAmendments == nil {
338			in.SuggestedAmendments = []TriageAmendment{}
339		}
340		if in.SuggestedFollowupBeads == nil {
341			in.SuggestedFollowupBeads = []FollowupBead{}
342		}
343		if in.Classification != "" && !isRecognizedTriageClassification(in.Classification) {
344			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("classification", "unknown classification", in.Classification))
345		}
346		if in.RecommendedAction != "" && !isRecognizedTriageRecommendedAction(in.RecommendedAction) {
347			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("recommended_action", "unknown recommended_action", in.RecommendedAction))
348		}
349		if len(in.DecodeWarnings) > 0 {
350			in.Malformed = true
351		}
352		return in
353	}
354	
355	func addTriageRequiredFieldWarnings(in TriageResult) TriageResult {
356		if strings.TrimSpace(in.Classification) == "" {
357			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("classification", "missing classification", ""))
358		}
359		if strings.TrimSpace(in.RecommendedAction) == "" {
360			in.DecodeWarnings = appendTriageDecodeWarning(in.DecodeWarnings, newTriageDecodeWarning("recommended_action", "missing recommended_action", ""))
361		}
362		if len(in.DecodeWarnings) > 0 {
363			in.Malformed = true
364		}
365		return in
366	}
