368	func decodeTriageAmendments(raw json.RawMessage) ([]TriageAmendment, []TriageDecodeWarning) {
369		if isEmptyTriageRaw(raw) {
370			return []TriageAmendment{}, nil
371		}
372		if s, ok := decodeTriageString(raw); ok {
373			if isTriageEmptySentinel(s) {
374				return []TriageAmendment{}, nil
375			}
376			return []TriageAmendment{}, []TriageDecodeWarning{newTriageDecodeWarning("suggested_amendments", "expected array; got string; dropped field", s)}
377		}
378		var out []TriageAmendment
379		if err := json.Unmarshal(raw, &out); err != nil {
380			return []TriageAmendment{}, []TriageDecodeWarning{newTriageDecodeWarning("suggested_amendments", "expected array; dropped malformed field", string(raw))}
381		}
382		if out == nil {
383			out = []TriageAmendment{}
384		}
385		return out, nil
386	}
