388	func decodeTriageFollowupBeads(raw json.RawMessage) ([]FollowupBead, []TriageDecodeWarning) {
389		if isEmptyTriageRaw(raw) {
390			return []FollowupBead{}, nil
391		}
392		if s, ok := decodeTriageString(raw); ok {
393			if isTriageEmptySentinel(s) {
394				return []FollowupBead{}, nil
395			}
396			return []FollowupBead{}, []TriageDecodeWarning{newTriageDecodeWarning("suggested_followup_beads", "expected array; got string; dropped field", s)}
397		}
398		var out []FollowupBead
399		if err := json.Unmarshal(raw, &out); err != nil {
400			return []FollowupBead{}, []TriageDecodeWarning{newTriageDecodeWarning("suggested_followup_beads", "expected array; dropped malformed field", string(raw))}
401		}
402		if out == nil {
403			out = []FollowupBead{}
404		}
405		return out, nil
406	}
