408	func malformedTriageResult(field, warning, raw string) TriageResult {
409		return TriageResult{
410			SuggestedAmendments:    []TriageAmendment{},
411			SuggestedFollowupBeads: []FollowupBead{},
412			DecodeWarnings:         []TriageDecodeWarning{newTriageDecodeWarning(field, warning, raw)},
413			Malformed:              true,
414		}
415	}
416	
417	func newTriageDecodeWarning(field, warning, raw string) TriageDecodeWarning {
418		return TriageDecodeWarning{
419			Field:      field,
420			Warning:    warning,
421			RawExcerpt: triageWarningExcerpt(raw),
422		}
423	}
424	
425	func appendTriageDecodeWarning(warnings []TriageDecodeWarning, next TriageDecodeWarning) []TriageDecodeWarning {
426		for _, existing := range warnings {
427			if existing.Field == next.Field && existing.Warning == next.Warning && existing.RawExcerpt == next.RawExcerpt {
428				return warnings
429			}
430		}
431		return append(warnings, next)
432	}
433	
434	func triageWarningExcerpt(raw string) string {
435		raw = strings.TrimSpace(raw)
436		if raw == "" {
437			return ""
438		}
439		raw = strings.Join(strings.Fields(raw), " ")
440		if len(raw) <= maxTriageWarningExcerptBytes {
441			return raw
442		}
443		const marker = "...[truncated]"
444		limit := maxTriageWarningExcerptBytes - len(marker)
445		if limit <= 0 {
446			return raw[:maxTriageWarningExcerptBytes]
447		}
448		return raw[:limit] + marker
449	}
450	
451	func formatTriageWarnings(warnings []TriageDecodeWarning) string {
452		if len(warnings) == 0 {
453			return "malformed triage output"
454		}
455		first := warnings[0]
456		if first.Field != "" && first.Warning != "" {
457			return first.Field + ": " + first.Warning
458		}
459		if first.Warning != "" {
460			return first.Warning
461		}
462		return "malformed triage output"
463	}
