465	func isEmptyTriageRaw(raw json.RawMessage) bool {
466		trimmed := strings.TrimSpace(string(raw))
467		return trimmed == "" || trimmed == "null"
468	}
469	
470	func decodeTriageString(raw json.RawMessage) (string, bool) {
471		var s string
472		if err := json.Unmarshal(raw, &s); err != nil {
473			return "", false
474		}
475		return strings.TrimSpace(s), true
476	}
