487	func isRecognizedTriageClassification(classification string) bool {
488		switch strings.TrimSpace(classification) {
489		case "already_satisfied",
490			"no_changes_unverified",
491			"no_changes_unjustified",
492			"needs_investigation",
493			"decomposed",
494			"blocked",
495			"superseded",
496			"routing",
497			"quota",
498			"transport",
499			"tests_red",
500			"merge_conflict",
501			"review_block",
502			"timeout",
503			"recoverable":
504			return true
505		default:
506			return false
507		}
508	}
509	
510	func isRecognizedTriageRecommendedAction(action string) bool {
511		switch strings.TrimSpace(action) {
512		case "close_already_satisfied",
513			"release_claim_retry",
514			"release_claim_needs_investigation",
515			"release_claim_mark_blocked",
516			"release_claim_mark_superseded",
517			"release_claim_wait_retry",
518			"close_decomposed_or_mark_execution_ineligible":
519			return true
520		default:
521			return false
522		}
523	}
