545	func resolveSessionLogPath(projectRoot, sessionID string) (string, bool) {
546		sessionID = strings.TrimSpace(sessionID)
547		if sessionID == "" {
548			return "", false
549		}
550		candidates := []string{sessionID}
551		base := filepath.Base(sessionID)
552		logDir := ResolveLogDir(projectRoot, "")
553		if base != "" {
554			candidates = append(candidates,
555				filepath.Join(logDir, base),
556				filepath.Join(logDir, "agent-"+base),
557				filepath.Join(logDir, "svc-"+base),
558			)
559			if filepath.Ext(base) == "" {
560				candidates = append(candidates,
561					filepath.Join(logDir, "agent-"+base+".jsonl"),
562					filepath.Join(logDir, "svc-"+base+".jsonl"),
563					filepath.Join(logDir, base+".jsonl"),
564				)
565			}
566		}
567		for _, candidate := range candidates {
568			if info, err := os.Stat(candidate); err == nil && !info.IsDir() {
569				return candidate, true
570			}
571		}
572		return "", false
573	}
574	
575	func readBoundedFileTail(path string, limitBytes int) (string, error) {
576		if limitBytes <= 0 {
577			return "", nil
578		}
579		f, err := os.Open(path)
580		if err != nil {
581			return "", err
582		}
583		defer f.Close()
584	
585		info, err := f.Stat()
586		if err != nil {
587			return "", err
588		}
589		size := info.Size()
590		if size <= 0 {
591			return "", nil
592		}
593		seek := int64(0)
594		if size > int64(limitBytes) {
595			seek = size - int64(limitBytes)
596		}
597		if _, err := f.Seek(seek, io.SeekStart); err != nil {
598			return "", err
599		}
600		data, err := io.ReadAll(f)
601		if err != nil {
602			return "", err
603		}
604		if seek > 0 {
605			return fmt.Sprintf("…[tail clipped to %d bytes]\n%s", limitBytes, string(data)), nil
606		}
607		return string(bytes.TrimSpace(data)), nil
608	}
