518	func preClaimIntakeRouteSummary(runtime AgentRunRuntime) string {
519		var fields []string
520		if runtime.ProfileOverride != "" {
521			fields = append(fields, "profile="+runtime.ProfileOverride)
522		}
523		if runtime.HarnessOverride != "" {
524			fields = append(fields, "harness="+runtime.HarnessOverride)
525		}
526		if runtime.ProviderOverride != "" {
527			fields = append(fields, "provider="+runtime.ProviderOverride)
528		}
529		if runtime.ModelOverride != "" {
530			fields = append(fields, "model="+runtime.ModelOverride)
531		}
532		return strings.Join(fields, " ")
533	}
