func TestReadinessStalExternalBlockerOverriddenByNewerNote(t *testing.T) {
	root := newPreClaimIntakeHookTestRoot(t)
	inner, candidate := newPreClaimIntakeHookTestStore(t, root)
	store := &parkCountingStore{claimCountingStore: &claimCountingStore{Store: inner}}

	// Seed an older no_changes_blocked event with an external blocker rationale,
	// simulating a prior attempt that identified a hard blocker.
	blockedBody, err := json.Marshal(map[string]any{
		"status": "no_changes",
		"detail": "bead readiness blocked: redpanda environment can support 32-partition stress test... prior_attempts show a hard external blocker: Redpanda fails to start due to AIO slot exhaustion on WSL2",
	})
	require.NoError(t, err)
	require.NoError(t, inner.AppendEvent(candidate.ID, bead.BeadEvent{
		Kind:      "bead-quality.triage",
		Summary:   "blocked: redpanda-blocker",
		Body:      string(blockedBody),
		Actor:     "agent",
		Source:    "ddx work",
		CreatedAt: time.Now().Add(-24 * time.Hour).UTC(),
	}))

	// Add a newer note explicitly saying the blocker was cleared.
	require.NoError(t, inner.Update(candidate.ID, func(b *bead.Bead) {
		b.Notes = "Unblocked 2026-05-18: the prior Redpanda/AIO blocker was stale after commit 90cd8348 bounded Redpanda test storage with an owned tmpfs mount... The container became ready and was cleaned up."
	}))

	// The readiness prompt should receive the note and consider it when evaluating
	// the prior blocker event. We'll verify that readiness classifies the bead as
	// actionable and includes the newer unblocked note in its rationale.
	svc := &preClaimIntakeHookServiceStub{
		finalText: `{"classification":"ready","tractability":"tractable","score":8,"rationale":"prior external blocker was cleared per latest operator notes; the bead is now actionable","readiness_checks":[{"reason":"hidden_external_blocker","verdict":"waived","evidence":"note: Unblocked 2026-05-18 cleared prior Redpanda blocker; container is ready","checkable_before_attempt":false}],"suggested_fixes":[],"waivers_applied":[{"reason":"cleared-by-operator-note","criteria":["hidden_external_blocker"],"evidence":"newer note explicitly clears stale blocker event"}]}`,
	}
	intakeHook := NewPreClaimIntakeHook(root, store, intakeHookTestConfig(), svc, nil)

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-stale-blocker-cleared",
				ResultRev: "cleared-blocker",
			}, nil
		}),
	}

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:               true,
		TargetBeadID:       candidate.ID,
		PreClaimIntakeHook: intakeHook,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// With the fix, readiness should classify as ready and proceed to claim/execution,
	// not be blocked by the stale external blocker event.
	assert.Equal(t, int32(1), atomic.LoadInt32(&store.claimCalls), "newer note clearing blocker must not prevent claim")
	assert.Equal(t, int32(0), atomic.LoadInt32(&store.parkCalls), "newer note clearing blocker must not park to proposed")
	assert.Equal(t, 1, result.Successes)

	got, err := inner.Get(candidate.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status, "bead should be closed after successful execution despite prior blocker history")
}
